/**
 * MedX shortcuts accessibility runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Keyboard shortcut registry and help.
 */
const SHORTCUTS_TOKENS = Object.freeze({
  primary: { value: "a11y-shortcuts-primary", scope: "a11y" },
  secondary: { value: "a11y-shortcuts-secondary", scope: "a11y" },
  muted: { value: "a11y-shortcuts-muted", scope: "a11y" },
  accent: { value: "a11y-shortcuts-accent", scope: "a11y" },
  surface: { value: "a11y-shortcuts-surface", scope: "a11y" },
});

const SHORTCUTS_PRESETS = Object.freeze({
  default: { token: "primary", enabled: true, priority: 1 },
  compact: { token: "secondary", enabled: true, priority: 2 },
  emphasis: { token: "accent", enabled: true, priority: 3 },
  subtle: { token: "muted", enabled: true, priority: 4 },
});

const SHORTCUTS_SUPPLY_CHAIN = Object.freeze({
  inventory: { label: "Inventory", key: "inventory", tier: "ops" },
  orders: { label: "Orders", key: "orders", tier: "ops" },
  compliance: { label: "Compliance", key: "compliance", tier: "regulatory" },
  coldChain: { label: "Cold chain", key: "cold-chain", tier: "ops" },
  blockchain: { label: "Blockchain", key: "blockchain", tier: "integrations" },
});

const shortcutsRegistry = new Map();
const SHORTCUTS_listeners = new Set();
let SHORTCUTS_seq = 0;

function createShortcutsId(prefix = "medx-a11y-shortcuts") {
  SHORTCUTS_seq += 1;
  return `${prefix}-${SHORTCUTS_seq}`;
}

function registerShortcuts(config = {}) {
  const entryId = config.id ?? createShortcutsId();
  const preset = SHORTCUTS_PRESETS[config.preset ?? "default"] ?? SHORTCUTS_PRESETS.default;
  const token = SHORTCUTS_TOKENS[config.token ?? preset.token] ?? SHORTCUTS_TOKENS.primary;
  const entry = {
    id: entryId,
    preset: config.preset ?? "default",
    token,
    domain: config.domain ?? "inventory",
    domainMeta: SHORTCUTS_SUPPLY_CHAIN[config.domain ?? "inventory"] ?? null,
    enabled: config.enabled ?? preset.enabled,
    priority: config.priority ?? preset.priority,
    metadata: config.metadata ?? {},
    createdAt: Date.now(),
    onChange: typeof config.onChange === "function" ? config.onChange : null,
  };
  shortcutsRegistry.set(entryId, entry);
  notifyShortcutsListeners("register", entry);
  return entry;
}

function updateShortcuts(id, patch = {}) {
  const entry = shortcutsRegistry.get(id);
  if (!entry) return null;
  Object.assign(entry, patch, { updatedAt: Date.now() });
  if (entry.onChange) entry.onChange(entry);
  notifyShortcutsListeners("update", entry);
  return entry;
}

function resolveShortcuts(id) {
  const entry = shortcutsRegistry.get(id);
  if (!entry) return null;
  return {
    id: entry.id,
    token: entry.token.value,
    domain: entry.domain,
    enabled: entry.enabled,
    priority: entry.priority,
    label: entry.domainMeta?.label ?? entry.domain,
  };
}

function listShortcutsEntries(filter = {}) {
  let items = Array.from(shortcutsRegistry.values());
  if (filter.domain) items = items.filter((e) => e.domain === filter.domain);
  if (filter.enabled != null) items = items.filter((e) => e.enabled === filter.enabled);
  return items.sort((a, b) => a.priority - b.priority);
}

function onShortcutsEvent(listener) {
  SHORTCUTS_listeners.add(listener);
  return () => SHORTCUTS_listeners.delete(listener);
}

function notifyShortcutsListeners(type, entry) {
  for (const listener of SHORTCUTS_listeners) {
    try {
      listener({ type, entry, registrySize: shortcutsRegistry.size });
    } catch (err) {
      console.warn("[medx:ui:a11y:shortcuts] listener error", err.message);
    }
  }
}

function getShortcutsMetrics() {
  const items = listShortcutsEntries();
  return {
    total: items.length,
    enabled: items.filter((e) => e.enabled).length,
    domains: [...new Set(items.map((e) => e.domain))],
    tokens: Object.keys(SHORTCUTS_TOKENS).length,
    presets: Object.keys(SHORTCUTS_PRESETS).length,
  };
}

async function runMedxShortcuts() {
  console.log("[medx:ui:a11y:shortcuts] runtime initialized");
  console.log(`[medx:ui:a11y:shortcuts] tokens=${Object.keys(SHORTCUTS_TOKENS).length} presets=${Object.keys(SHORTCUTS_PRESETS).length}`);

  const events = [];
  onShortcutsEvent((e) => events.push(e.type));

  const domains = Object.keys(SHORTCUTS_SUPPLY_CHAIN);
  const presets = Object.keys(SHORTCUTS_PRESETS);
  for (let i = 0; i < domains.length; i += 1) {
    registerShortcuts({
      domain: domains[i],
      preset: presets[i % presets.length],
      metadata: { seed: i, module: "a11y/shortcuts" },
    });
  }

  const first = listShortcutsEntries()[0];
  if (first) updateShortcuts(first.id, { priority: 0, metadata: { ...first.metadata, promoted: true } });

  const metrics = getShortcutsMetrics();
  const resolved = first ? resolveShortcuts(first.id) : null;

  console.log(`[medx:ui:a11y:shortcuts] registered=${metrics.total} enabled=${metrics.enabled}`);
  console.log(`[medx:ui:a11y:shortcuts] domains=${metrics.domains.join(",")}`);
  console.log(`[medx:ui:a11y:shortcuts] events=${events.join(",")}`);
  if (resolved) console.log(`[medx:ui:a11y:shortcuts] sample=${resolved.token}:${resolved.domain}`);
  console.log("[medx:ui:a11y:shortcuts] bootstrap complete");
}

module.exports = runMedxShortcuts;
